}
```

This feels complicated. Any way to make it simpler? Maybe something like:

```python
import collections

class Missing(dict):

    def __init__(self):
        self.touched = False

    def __missing__(self, key):
        self.touched = True
        return '\t'
    
def format_thing(template: str, **kwargs):
    unknowns = Missing()
    rendered = template.format_map(collections.ChainMap(kwargs, unknowns))
    if unknowns.touched:
        return rendered.replace('\t/', '')
    return rendered

print(format_thing('hello/world/{x}/{y}/{name}/{other}', name='foo'))
```

