Style: Set the variable and then unset it like that is a bit off in terms of flow.
How about:

```go
var found bool
for _, prefix := range prefixes {
  candidate := prefix + name
  if _, exists := seen[candidate]; exists {
    continue
  }
  name = candidate
  found = true
  seen[name] = struct{}
  break
}

if !found {
  return
}
```

